import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";

import { AlertError } from "../../fscommon";
import {
  FieldBool,
  FieldRelation,
  useContentEditContext,
} from "../../fspage-content-form";

import type { FieldApiOnChangeType } from "../../fsform/fsform";
import type { RelationFieldDefinition } from "fastschema";

export const AccessRoles = () => {
  const { form, schemaDef } = useContentEditContext();
  const fieldRoles = schemaDef.fields.find((f) => f.name === "roles");
  const fieldActive = schemaDef.fields.find((f) => f.name === "active");
  if (!fieldRoles || !fieldActive) {
    return (
      <AlertError
        error={new Error("Roles or Active field not found in user schema")}
      />
    );
  }

  return (
    <Card>
      <CardHeader className="flex flex-row items-center justify-between">
        <CardTitle>Access & Roles</CardTitle>
        <form.Field
          name="active"
          children={(field) => (
            <FieldBool
              fieldDef={(() => {
                fieldActive.label = "Active account";
                return fieldActive;
              })()}
              fieldApi={field as unknown as FieldApiOnChangeType}
              renderer="switch_right"
              className="w-auto"
            />
          )}
        />
      </CardHeader>
      <CardContent className="space-y-4">
        <div className="space-y-2">
          <form.Field
            name="roles"
            children={(fieldApi) => {
              return (
                <FieldRelation
                  fieldDef={fieldRoles as RelationFieldDefinition}
                  fieldApi={fieldApi as unknown as FieldApiOnChangeType}
                />
              );
            }}
          />

          <p className="text-muted-foreground text-xs">
            Assign permissions by selecting roles from the list.
          </p>
        </div>
      </CardContent>
    </Card>
  );
};

import { useStore } from "@tanstack/react-form";
import { getSchemaField } from "fastschema";
import { SaveIcon } from "lucide-react";

import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";

import { FormErrors } from "../../fsform/error";
import {
  FieldRenderer,
  useContentEditContext,
} from "../../fspage-content-form";

import type { FieldApiOnChangeType } from "../../fsform/fsform";
import type { FieldDefinition as FD } from "fastschema";

export const AccountInfo = () => {
  const { form, isEditing, schemaDef } = useContentEditContext();
  const formErrors = useStore(form.store, (state) => state.errors);
  const passwordField = getSchemaField(schemaDef, "password");
  const passwordConfirmField = {
    ...passwordField,
    name: "password_confirmation",
    label: "Confirm Password",
  };

  return (
    <section className="space-y-6">
      <div className="flex flex-row items-center">
        <div>
          <h1 className="text-xl font-semibold tracking-tight">
            {isEditing ? "Edit User" : "Create New User"}
          </h1>
          <p className="text-muted-foreground text-sm">
            {isEditing
              ? "Update the user account details."
              : "Fill in the details below to onboard a new user into the system."}
          </p>
        </div>
        <div className="ml-auto flex items-center gap-2">
          <FormErrors errors={formErrors} />
          <form.Subscribe
            selector={(state) => [state.canSubmit, state.isSubmitting]}
            children={([canSubmit, isSubmitting]) => (
              <Button
                type="submit"
                size="sm"
                disabled={!canSubmit || isSubmitting || formErrors.length > 0}
              >
                <SaveIcon className="size-3.5" />
                {isSubmitting
                  ? "Saving..."
                  : isEditing
                    ? "Update User"
                    : "Create User"}
              </Button>
            )}
          />
        </div>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Account Information</CardTitle>
        </CardHeader>
        <CardContent className="grid grid-cols-1 gap-6 md:grid-cols-2">
          <form.Field
            name="username"
            children={(field) => (
              <FieldRenderer
                fieldDef={getSchemaField(schemaDef, "username") as FD}
                fieldApi={field as unknown as FieldApiOnChangeType}
              />
            )}
          />

          <form.Field
            name="email"
            children={(field) => (
              <FieldRenderer
                fieldDef={getSchemaField(schemaDef, "email") as FD}
                fieldApi={field as unknown as FieldApiOnChangeType}
              />
            )}
          />

          <form.Field
            name="password"
            children={(field) => (
              <FieldRenderer
                fieldDef={passwordField as FD}
                fieldApi={field as unknown as FieldApiOnChangeType}
                renderer="password"
              />
            )}
          />

          <form.Field
            name="password_confirmation"
            children={(field) => {
              return (
                <FieldRenderer
                  fieldDef={passwordConfirmField as FD}
                  fieldApi={field as unknown as FieldApiOnChangeType}
                  renderer="password"
                />
              );
            }}
          />
        </CardContent>
      </Card>
    </section>
  );
};

import { SYSTEM_USER_FIELDS, type SchemaDefinition } from "fastschema";
import { Settings2 } from "lucide-react";

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { FieldGroup } from "@/components/ui/field";
import { useContentEditContext } from "@/components/fsui/fspage-content-form/context";
import { FieldRenderer } from "@/components/fsui/fspage-content-form/fields-v2";

import type { FieldProps } from "@/components/fsui/fspage-content-form/types";

export const getUserCustomFields = (schemaDef?: SchemaDefinition) =>
  schemaDef?.fields?.filter(
    (f) =>
      !(SYSTEM_USER_FIELDS as readonly string[]).includes(f.name) &&
      !f.immutable,
  ) || [];

export const CustomFields = () => {
  const { form, schemaDef } = useContentEditContext();
  const customFields = getUserCustomFields(schemaDef);
  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Settings2 className="text-muted-foreground size-5" />
          Custom Fields
        </CardTitle>
      </CardHeader>
      <CardContent>
        {customFields.length === 0 ? (
          <p className="text-muted-foreground text-sm">
            No custom fields defined for this schema.
          </p>
        ) : (
          <FieldGroup>
            {customFields.map((fieldDef) => (
              <form.Field
                key={fieldDef.name}
                name={fieldDef.name}
                children={(fieldApi) => {
                  const props: FieldProps = {
                    fieldDef,
                    value: fieldApi.state.value,
                    onChange: fieldApi.handleChange,
                    onBlur: fieldApi.handleBlur,
                  };
                  return <FieldRenderer {...props} />;
                }}
              />
            ))}
          </FieldGroup>
        )}
      </CardContent>
    </Card>
  );
};

import { getSchemaField } from "fastschema";
import { KeyRound } from "lucide-react";

import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Field, FieldError } from "@/components/ui/field";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";

import {
  FieldRenderer,
  useContentEditContext,
} from "../../fspage-content-form";

import type { FieldApiOnChangeType } from "../../fsform/fsform";
import type { FieldDefinition as FD } from "fastschema";

export const OAuthProvider = () => {
  const { form, schemaDef } = useContentEditContext();

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <KeyRound className="text-muted-foreground size-5" />
          OAuth Provider Info
        </CardTitle>
      </CardHeader>
      <CardContent className="space-y-4">
        <form.Field
          name="provider"
          children={(field) => (
            <FieldRenderer
              fieldDef={getSchemaField(schemaDef, "provider") as FD}
              fieldApi={field as unknown as FieldApiOnChangeType}
            />
          )}
        />

        <form.Field
          name="provider_id"
          children={(field) => (
            <FieldRenderer
              fieldDef={getSchemaField(schemaDef, "provider_id") as FD}
              fieldApi={field as unknown as FieldApiOnChangeType}
            />
          )}
        />

        <form.Field
          name="provider_username"
          children={(field) => (
            <FieldRenderer
              fieldDef={getSchemaField(schemaDef, "provider_username") as FD}
              fieldApi={field as unknown as FieldApiOnChangeType}
            />
          )}
        />

        <form.Field
          name="provider_profile_image"
          children={(field) => {
            const isInvalid =
              field.state.meta.isTouched && !field.state.meta.isValid;
            const avatarUrl = (field.state.value as string) ?? "";
            return (
              <div className="flex items-center gap-4">
                <Avatar className="border-border size-12 border">
                  {avatarUrl && (
                    <AvatarImage
                      src={avatarUrl}
                      alt="Avatar"
                    />
                  )}
                  <AvatarFallback className="bg-muted text-muted-foreground">
                    ?
                  </AvatarFallback>
                </Avatar>
                <Field
                  data-invalid={isInvalid}
                  className="flex-1"
                >
                  <Label htmlFor="provider_profile_image">Avatar URL</Label>
                  <Input
                    id="provider_profile_image"
                    name="provider_profile_image"
                    type="text"
                    value={avatarUrl}
                    onBlur={field.handleBlur}
                    onChange={(e) => field.handleChange(e.target.value)}
                    aria-invalid={isInvalid}
                    placeholder="https://..."
                  />
                  {isInvalid && <FieldError errors={field.state.meta.errors} />}
                </Field>
              </div>
            );
          }}
        />
      </CardContent>
    </Card>
  );
};

