import {
  USER_MUTABLE_FIELDS,
  userFormSchema,
  type SchemaDefinition,
  type User,
  type UserFormValues,
} from "fastschema";

import { ContentEditContext } from "../fspage-content-form";
import { useCreateContentForm } from "../fspage-content-form/use-create-content-form";

import { AccessRoles } from "./_components/access-roles";
import { AccountInfo } from "./_components/account-info";
import { CustomFields } from "./_components/custom-fields";
import { OAuthProvider } from "./_components/oauth-provider";
import { PersonalDetails } from "./_components/personal-details";
import { ProfileImage } from "./_components/profile-image";

import type { UseFormReturnOnChangeType } from "../fsform/fsform";

export interface UserEditPageProps {
  schemaDef: SchemaDefinition;
  initialData?: User;
  onSubmit: (data: UserFormValues) => Promise<void> | void;
}

export const UserEditPage = ({
  schemaDef,
  initialData,
  onSubmit,
}: UserEditPageProps) => {
  const { form, pkValue, getField } = useCreateContentForm({
    schemaDef,
    initialData: (initialData || {
      active: true,
    }) as UserFormValues | undefined,
    withFiles: true,
    mutableFields: USER_MUTABLE_FIELDS as readonly string[],
    zodSchema: userFormSchema,
    onSubmit: (data) => {
      delete data.password_confirmation;
      if (!data.password) {
        delete data.password;
      }
      onSubmit(data as UserFormValues);
    },
  });

  return (
    <ContentEditContext.Provider
      value={{
        form: form as unknown as UseFormReturnOnChangeType,
        schemaDef,
        pkValue,
        getField,
      }}
    >
      <form
        onSubmit={(e) => {
          e.preventDefault();
          form.handleSubmit();
        }}
      >
        <div className="flex flex-col gap-6">
          <AccountInfo />

          <div className="grid grid-cols-1 gap-6 lg:grid-cols-3">
            <div className="lg:col-span-2">
              <PersonalDetails />
            </div>
            <div>
              <ProfileImage />
            </div>
          </div>

          <AccessRoles />

          <div className="grid grid-cols-1 gap-6 lg:grid-cols-2">
            <OAuthProvider />
            <CustomFields />
          </div>
        </div>
      </form>
    </ContentEditContext.Provider>
  );
};
